args.mermaid_code:
flowchart TD
    A([Security Posture Overview]) --> B[Azure Policy Compliance]
    A --> C[Security Events Review]

    B --> D{Overall Status}
    D -->|Partially Compliant| E[Compliant Findings\n- Network Watcher monitoring enabled\n- SQL DB encryption monitoring\n- Redis diagnostics logs monitoring\n- Key Vault soft delete monitoring]
    D -->|Needs Remediation| F[Non-Compliant Findings\n- VNet DDoS protection monitoring: 3 resources\n- Azure Firewall effect: 1 resource\n- Redis private endpoint monitoring: 2 resources\n- Logic Apps diagnostics logs: 3 resources\n- Key Vault purge protection monitoring: 2 resources\n- Key Vault firewall monitoring: 1 resource]

    C --> G{Log Query Result}
    G -->|No matches| H[No security-related events found\nin last 7 days]

    E --> I[Posture: Needs Remediation]
    F --> I
    H --> I

    classDef good fill:#dff7df,stroke:#2e7d32,color:#1b5e20;
    classDef bad fill:#fde0e0,stroke:#c62828,color:#8e0000;
    classDef neutral fill:#eeeeee,stroke:#616161,color:#424242;
    classDef warn fill:#fff3cd,stroke:#f0ad4e,color:#8a6d3b;

    class A,I warn;
    class E good;
    class F bad;
    class H neutral;
